const criticOutput = $input.first().json.text;

let loci = [];
try {
  const cleaned = criticOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  loci = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse critic output', raw: criticOutput } }];
}

if (!Array.isArray(loci) || loci.length === 0) {
  return [{ json: { skipped: true, reason: 'No qualifying loci found' } }];
}

return loci.map((locus, index) => ({
  json: {
    locus_id: `ALDB-${Date.now()}-${index}`,
    gene: locus.gene || null,
    rsid: locus.rsid || null,
    chromosome: locus.chromosome || null,
    position_hg38: locus.position_hg38 || null,
    population: locus.population || null,
    environment_category: locus.environment_category || null,
    selection_tests: locus.selection_tests || null,
    selection_statistic_value: locus.selection_statistic_value || null,
    derived_allele_freq: locus.derived_allele_freq || null,
    proposed_mechanism: locus.proposed_mechanism || null,
    tier: locus.tier || null,
    tier_rationale: locus.tier_rationale || null,
    source_doi: locus.source_doi || null,
    source_title: locus.source_title || null,
    status: locus.status || 'flagged_for_review',
    flag_reason: locus.flag_reason || null,
    extracted_by: 'agent',
    extraction_date: locus.extraction_date || new Date().toISOString()
  }
}));
